"use client";

import type { Transition, UseInViewOptions } from "motion/react";
import { motion, useInView } from "motion/react";
import type {
  ElementType} from "react";
import {
  forwardRef,
  useEffect,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
} from "react";

import { cn } from "@/lib/utils";

type HighlightDirection = "ltr" | "rtl" | "ttb" | "btt";

type TextHighlighterProps = {
  children: React.ReactNode; // The text content to be highlighted
  as?: ElementType; // HTML element to render as (default: "p")
  triggerType?: "hover" | "ref" | "inView" | "auto"; //How to trigger the animation (default: "inView")
  transition?: Transition; // Animation transition configuration (default: { duration: 0.4, type: "spring", bounce: 0 })
  useInViewOptions?: UseInViewOptions; // Options for useInView hook when triggerType is "inView"
  className?: string; // Class name for the container element
  highlightColor?: string;
  // Highlight color (CSS color string). Also can be a function that returns a color string, eg: 'hsl(60, 90%, 68%)' (yellow)
  direction?: HighlightDirection; // Direction of the highlight animation (default: "ltr" (left to right))
} & React.HTMLAttributes<HTMLElement>;

export interface TextHighlighterRef {
  animate: (direction?: HighlightDirection) => void; // Trigger the highlight animation
  reset: () => void; // Reset the highlight animation
}

export const TextHighlighter = forwardRef<
  TextHighlighterRef,
  TextHighlighterProps
>(
  (
    {
      children,
      as = "span",
      triggerType = "inView",
      transition = { bounce: 0, delay: 0, duration: 1, type: "spring" },
      useInViewOptions = {
        amount: 0.1,
        initial: false,
        once: true,
      },
      className,
      highlightColor = "hsl(25, 90%, 80%)",
      direction = "ltr",
      ...props
    },
    ref
  ) => {
    const componentRef = useRef<HTMLDivElement>(null);
    const [isAnimating, setIsAnimating] = useState(false);
    const [isHovered, setIsHovered] = useState(false);
    const [currentDirection, setCurrentDirection] =
      useState<HighlightDirection>(direction);

    // this allows us to change the direction whenever the direction prop changes
    useEffect(() => {
      setCurrentDirection(direction);
    }, [direction]);

    const isInView =
      triggerType === "inView"
        ? useInView(componentRef, useInViewOptions)
        : false;

    useImperativeHandle(ref, () => ({
      animate: (animationDirection?: HighlightDirection) => {
        if (animationDirection) {
          setCurrentDirection(animationDirection);
        }
        setIsAnimating(true);
      },
      reset: () => setIsAnimating(false),
    }));

    const shouldAnimate =
      triggerType === "hover"
        ? isHovered
        : triggerType === "inView"
          ? isInView
          : triggerType === "ref"
            ? isAnimating
            : triggerType === "auto"
              ? true
              : false;

    const ElementTag = as || "span";

    // Get background size based on direction
    const getBackgroundSize = (animated: boolean) => {
      switch (currentDirection) {
        case "ltr": {
          return animated ? "100% 100%" : "0% 100%";
        }
        case "rtl": {
          return animated ? "100% 100%" : "0% 100%";
        }
        case "ttb": {
          return animated ? "100% 100%" : "100% 0%";
        }
        case "btt": {
          return animated ? "100% 100%" : "100% 0%";
        }
        default: {
          return animated ? "100% 100%" : "0% 100%";
        }
      }
    };

    // Get background position based on direction
    const getBackgroundPosition = () => {
      switch (currentDirection) {
        case "ltr": {
          return "0% 0%";
        }
        case "rtl": {
          return "100% 0%";
        }
        case "ttb": {
          return "0% 0%";
        }
        case "btt": {
          return "0% 100%";
        }
        default: {
          return "0% 0%";
        }
      }
    };

    const animatedSize = useMemo(
      () => getBackgroundSize(shouldAnimate),
      [shouldAnimate, currentDirection]
    );
    const initialSize = useMemo(
      () => getBackgroundSize(false),
      [currentDirection]
    );
    const backgroundPosition = useMemo(
      () => getBackgroundPosition(),
      [currentDirection]
    );

    const highlightStyle = {
      WebkitBoxDecorationBreak: "clone",
      backgroundImage: `linear-gradient(${highlightColor}, ${highlightColor})`,
      backgroundPosition: backgroundPosition,
      backgroundRepeat: "no-repeat",
      backgroundSize: animatedSize,
      boxDecorationBreak: "clone",
    } as React.CSSProperties;

    return (
      <ElementTag
        ref={componentRef}
        onMouseEnter={() => triggerType === "hover" && setIsHovered(true)}
        onMouseLeave={() => triggerType === "hover" && setIsHovered(false)}
        {...props}
      >
        <motion.span
          className={cn("inline", className)}
          style={highlightStyle}
          animate={{
            backgroundSize: animatedSize,
          }}
          initial={{
            backgroundSize: initialSize,
          }}
          transition={transition}
        >
          {children}
        </motion.span>
      </ElementTag>
    );
  }
);

TextHighlighter.displayName = "TextHighlighter";

export default TextHighlighter;

